import { LeagueTable } from '../../objects/league-table';

interface LeagueTableRowComponentProps
{
    leagueTableRow : LeagueTable
}

const LeagueTableRow = (leagueTableProps : LeagueTableRowComponentProps) => {
    
    
    return(  
        <>
        <tr>
            <td >{leagueTableProps.leagueTableRow.teamName}</td>
            <td >{leagueTableProps.leagueTableRow.pld}</td>
            <td >{leagueTableProps.leagueTableRow.won}</td>
            <td >{leagueTableProps.leagueTableRow.drawn}</td>
            <td >{leagueTableProps.leagueTableRow.lost}</td>
            <td >{leagueTableProps.leagueTableRow.glsFor}</td>
            <td >{leagueTableProps.leagueTableRow.glsA}</td>
            <td >{leagueTableProps.leagueTableRow.gd}</td>
            <td >{leagueTableProps.leagueTableRow.points}</td>  
            <td >{leagueTableProps.leagueTableRow.achieveablePoints}</td>
        </tr>                
        </>   
    )
}               
export default LeagueTableRow;
